  ('dietitian-moex-07578', 'dietitian', 'dietitian-moex-101-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '有關丙酮酸脫氫（pyruvate dehydrogenase）特性之敘述，下列何者錯誤？', '["需輔thiamine pyrophosphate之參與", "此酵素催化丙酮酸進行脫羧反應（decarboxylation）", "此酵素與NAD＋相連結", "ATP會抑制此酵素活性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:47+00:00", "source_pdf_sha1": "ca8a32319b8e", "answer_pdf_sha1": "3a1bf1c1b455", "source_family": "moex-gov-tw", "moex": {"exam_code": "101110", "c": "105", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "101", "exam_name": "101年第2次醫事人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
